  const rootForComparison = shouldCompareCaseInsensitive ? normalizedRoot.toLowerCase() : normalizedRoot;
  const sourceIsInsideRoot = normalizedRoot.length > 0 && sourceForComparison.startsWith(rootForComparison + "/");
  const relativeSource = sourceIsInsideRoot ? source.slice(normalizedRoot.length + 1) : source;
  return `${stripLeadingDotSlash(relativeSource)}:${location.line}`;
